{"content":"import React from 'react';
import { Coins } from 'lucide-react';
import ThemeToggle from '../ui/ThemeToggle';
import SearchBar from '../ui/SearchBar';

interface HeaderProps {
  credits: number;
  user: { name: string; email: string } | null;
  onOpenCommandPalette?: () => void;
  onLogoClick?: () => void;
}

export default function Header({
  credits,
  user,
  onOpenCommandPalette,
  onLogoClick,
}: HeaderProps) {
  return (
    <header className="h-12 shrink-0 bg-[var(--bg-surface)] border-b border-[var(--border-default)] flex items-center px-4 gap-4 z-30">
      {/* Left — Logo */}
      <div
        className="flex items-center cursor-pointer shrink-0 mr-2"
        onClick={onLogoClick}
      >
        <span className="text-[var(--text-primary)] font-bold text-[15px] tracking-tight">Cited</span>
        <span className="text-[var(--accent)] font-bold text-[15px]">By</span>
        <span className="text-[var(--text-tertiary)] font-normal text-[13px]">.io</span>
      </div>

      {/* Center — Search */}
      <div className="flex-1 flex justify-center">
        <SearchBar onOpen={onOpenCommandPalette} />
      </div>

      {/* Right — Credits + Theme + Avatar */}
      <div className="flex items-center gap-3 shrink-0">
        {user && (
          <div className="flex items-center gap-1.5 text-[13px] text-[var(--text-secondary)]">
            <Coins className="w-3.5 h-3.5 text-[var(--accent)]" />
            <span className="font-medium text-[var(--text-primary)]">{credits}</span>
          </div>
        )}

        <ThemeToggle />

        {user && (
          <div className="w-7 h-7 rounded-full bg-gradient-to-br from-emerald-500 to-teal-600 flex items-center justify-center text-[11px] text-white font-semibold ring-1 ring-[var(--border-default)]">
            {user.name?.charAt(0)?.toUpperCase() || 'U'}
          </div>
        )}
      </div>
    </header>
  );
}
"}

