{"content":"import React from 'react';
import { AnalysisResult } from '../types';
import HeroWelcome from '../components/dashboard/HeroWelcome';
import StatsOverview from '../components/dashboard/StatsOverview';
import DualModelExplainer from '../components/dashboard/DualModelExplainer';
import QuickActions from '../components/dashboard/QuickActions';

interface DashboardProps {
  onBack: () => void;
  history: AnalysisResult[];
  onView: (analysis: AnalysisResult) => void;
  onNavigate: (view: any) => void;
}

const Dashboard: React.FC<DashboardProps> = ({ onBack, history, onView, onNavigate }) => {
  // TODO: These will come from Supabase/auth context later
  const userName = 'Utilisateur';
  const planName = 'Pro';
  const credits = 142;
  const maxCredits = 200;

  // Derive stats from history if available
  const lastAuditScore = history.length > 0 ? history[0].globalScore : null;
  const citationCount = history.reduce((sum, h) => sum + (h.aiCitation?.probability > 50 ? 1 : 0), 0);
  const languagesCount = 0;
  const alertsCount = 0;

  return (
    <div className="space-y-10 page-enter">
      {/* SECTION 1 — Hero Welcome */}
      <HeroWelcome
        userName={userName}
        planName={planName}
        credits={credits}
        maxCredits={maxCredits}
        onNavigate={onNavigate}
      />

      {/* SECTION 2 — Stats rapides */}
      <StatsOverview
        stats={{
          aeoScore: lastAuditScore,
          citationCount,
          languagesAnalyzed: languagesCount,
          activeAlerts: alertsCount,
        }}
      />

      {/* SECTION 3 — Double modele economique */}
      <DualModelExplainer
        credits={credits}
        maxCredits={maxCredits}
        planName={planName}
        currentPlan={planName.toLowerCase() as 'free' | 'starter' | 'pro' | 'agence'}
        onNavigate={onNavigate}
      />

      {/* SECTION 4 — Actions rapides */}
      <QuickActions
        credits={credits}
        onNavigate={onNavigate}
      />
    </div>
  );
};

export default Dashboard;
"}

{"content":"import React, { createContext, useContext, useEffect, useState } from 'react';

type Theme = 'light' | 'dark';

interface ThemeContextValue {
  theme: Theme;
  toggleTheme: () => void;
  setTheme: (theme: Theme) => void;
}

const ThemeContext = createContext<ThemeContextValue>({
  theme: 'light',
  toggleTheme: () => {},
  setTheme: () => {},
});

const STORAGE_KEY = 'citedby-theme';

function getInitialTheme(): Theme {
  if (typeof window === 'undefined') return 'light';
  const stored = localStorage.getItem(STORAGE_KEY);
  if (stored === 'light' || stored === 'dark') return stored;
  return window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';
}

export function ThemeProvider({ children }: { children: React.ReactNode }) {
  const [theme, setThemeState] = useState<Theme>(getInitialTheme);

  useEffect(() => {
    const root = document.documentElement;
    if (theme === 'dark') {
      root.classList.add('dark');
    } else {
      root.classList.remove('dark');
    }
    document.body.style.backgroundColor = '';
    document.body.className = '';
    localStorage.setItem(STORAGE_KEY, theme);
  }, [theme]);

  const toggleTheme = () => setThemeState(prev => (prev === 'light' ? 'dark' : 'light'));
  const setTheme = (t: Theme) => setThemeState(t);

  return (
    <ThemeContext.Provider value={{ theme, toggleTheme, setTheme }}>
      {children}
    </ThemeContext.Provider>
  );
}

export function useTheme() {
  return useContext(ThemeContext);
}
"}

